import{_ as o,c as t,a0 as r,o as l}from"./chunks/framework.BOr1CWtK.js";const h=JSON.parse('{"title":"Holobro X500 Drone Setup Guide","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"docs/holybro/setup.md","filePath":"docs/holybro/setup.md"}'),a={name:"docs/holybro/setup.md"};function i(n,e,s,p,d,c){return l(),t("div",null,e[0]||(e[0]=[r('<h1 id="holobro-x500-drone-setup-guide" tabindex="-1">Holobro X500 Drone Setup Guide <a class="header-anchor" href="#holobro-x500-drone-setup-guide" aria-label="Permalink to &quot;Holobro X500 Drone Setup Guide&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><div class="margin"><p>This guide provides detailed steps to set up your Holobro X500 drone using Ardupilot firmware. Since the drone is large and not easily connected to a laptop or PC, we will use a telemetry module for wireless communication. This will allow you to calibrate the drone and access telemetry data efficiently.</p></div><h2 id="step-1-choose-firmware-type" tabindex="-1">Step 1: Choose Firmware Type <a class="header-anchor" href="#step-1-choose-firmware-type" aria-label="Permalink to &quot;Step 1: Choose Firmware Type&quot;">​</a></h2><p><strong>Ardupilot Firmware</strong></p><div class="margin"><p>Ardupilot is a robust open-source firmware designed for various types of drones, supporting advanced features like autonomous flight, waypoint navigation, and mission planning. It is continuously updated by a dedicated community. Download the latest version suitable for your flight controller from the official Ardupilot repository.</p></div><h2 id="step-2-choose-flight-controller-type" tabindex="-1">Step 2: Choose Flight Controller Type <a class="header-anchor" href="#step-2-choose-flight-controller-type" aria-label="Permalink to &quot;Step 2: Choose Flight Controller Type&quot;">​</a></h2><p>Select the appropriate flight controller for your drone. Examples include:</p><ul><li>Pixhawk 6</li></ul><h2 id="step-3-download-or-build-firmware" tabindex="-1">Step 3: Download or Build Firmware <a class="header-anchor" href="#step-3-download-or-build-firmware" aria-label="Permalink to &quot;Step 3: Download or Build Firmware&quot;">​</a></h2><ul><li><strong>Ardupilot Firmware:</strong> <a href="https://firmware.ardupilot.org/Copter/" target="_blank" rel="noreferrer">Download from Ardupilot Firmware</a></li><li><strong>Firmware File Types:</strong> Obtain any of the following: <code>.hex</code>, <code>.apj</code>, or <code>.elf</code>.</li><li><strong>Installation:</strong> If you choose <code>.hex</code> or <code>.elf</code>, download the <a href="https://www.st.com/en/development-tools/stm32cubeprog.html" target="_blank" rel="noreferrer">STM32 CUBE PROGRAMMER</a>. If you choose <code>.apj</code>, download <a href="https://ardupilot.org/planner/docs/mission-planner-installation.html" target="_blank" rel="noreferrer">Mission Planner</a>.</li></ul><h2 id="step-4-flash-firmware-to-flight-controller" tabindex="-1">Step 4: Flash Firmware to Flight Controller <a class="header-anchor" href="#step-4-flash-firmware-to-flight-controller" aria-label="Permalink to &quot;Step 4: Flash Firmware to Flight Controller&quot;">​</a></h2><ol><li><p><strong>Using Cube Programmer (<code>.hex</code> or <code>.elf</code>)</strong></p><div class="flex-setup"><p><strong>Step 1:</strong> Press and hold the boot button while connecting the power cable to your PC.</p><p><strong>Step 2:</strong> Open Cube Programmer and select the USB option; ensure you see PORT: USB1.</p><span class="note">Note: If USB1 isn&#39;t detected, repeat Step 1.</span><p><strong>Step 3:</strong> Connect and open the `.hex` or `.elf` file.</p><p><strong>Step 4:</strong> Click the Download button and wait for completion. Disconnect the cable afterwards.</p></div></li><li><p><strong>Using Mission Planner (<code>.apj</code>)</strong></p><div class="flex-setup"><p><strong>Step 1:</strong> Use a smaller device to connect via the data cable and check for the COM port.</p><p><strong>Step 2:</strong> Click &quot;Initial Setup,&quot; then &quot;Install Firmware,&quot; and select &quot;Load custom firmware.&quot;</p><p><strong>Step 3:</strong> Open the `.apj` file to initiate the firmware download.</p></div><p><em>For further details, <a href="https://ardupilot.org/planner/docs/common-loading-firmware-onto-pixhawk.html" target="_blank" rel="noreferrer">refer to Ardupilot documentation</a>.</em></p></li></ol><h2 id="step-5-connect-telemetry-module" tabindex="-1">Step 5: Connect Telemetry Module <a class="header-anchor" href="#step-5-connect-telemetry-module" aria-label="Permalink to &quot;Step 5: Connect Telemetry Module&quot;">​</a></h2><ol><li><p><strong>Connect the Telemetry Module:</strong></p><ul><li>Connect the telemetry module to your flight controller using the appropriate pins (TX/RX).</li><li>Power the telemetry module separately if needed.</li></ul></li><li><p><strong>Install Telemetry Software:</strong></p><ul><li>Open Mission Planner on a compatible device.</li><li>Select the correct COM port for the telemetry module.</li><li>Click <strong>Connect</strong> to establish communication with the drone.</li></ul></li></ol><h2 id="step-6-configure-parameters" tabindex="-1">Step 6: Configure Parameters <a class="header-anchor" href="#step-6-configure-parameters" aria-label="Permalink to &quot;Step 6: Configure Parameters&quot;">​</a></h2><ol><li><p><strong>Open Mission Planner:</strong></p><ul><li>Ensure you are connected via the telemetry module.</li><li>Click on the COM port at the top right and connect.</li></ul></li><li><p><strong>Navigate to Config in the Navigation Bar:</strong></p><ul><li>Select <strong>Full Parameter List</strong>.</li><li>Click <strong>Load From File</strong> and upload the parameter file (e.g., <code>swiftProMax.param</code>).</li><li>Confirm the upload by clicking <strong>Write parameters</strong>.</li></ul></li></ol><h2 id="step-7-calibrate-test-drone" tabindex="-1">Step 7: Calibrate &amp; Test Drone <a class="header-anchor" href="#step-7-calibrate-test-drone" aria-label="Permalink to &quot;Step 7: Calibrate &amp; Test Drone&quot;">​</a></h2><ol><li><p><strong>Connect to Mission Planner:</strong></p><ul><li>Open Mission Planner and connect via the telemetry module.</li></ul></li><li><p><strong><a href="https://ardupilot.org/copter/docs/common-accelerometer-calibration.html#id2" target="_blank" rel="noreferrer">Accelerometer Calibration</a></strong></p><ul><li>Go to the Setup Icon, then &quot;Accel Calibration.&quot;</li><li>Follow prompts for 3-axis calibration and confirm success.</li></ul></li><li><p><strong><a href="https://ardupilot.org/copter/docs/common-compass-calibration-in-mission-planner.html" target="_blank" rel="noreferrer">Compass Calibration</a></strong></p><ul><li>Select &quot;Compass&quot; in <strong>Mandatory Hardware</strong>.</li><li>Follow the calibration instructions.</li></ul></li><li><p><strong><a href="https://ardupilot.org/planner/docs/common-radio-control-calibration.html#common-radio-control-calibration" target="_blank" rel="noreferrer">Radio Calibration</a></strong></p><ul><li>Ensure the RadioMaster is connected.</li><li>Perform the radio calibration and verify response.</li></ul></li><li><p><strong>Flight Mode Configuration</strong></p><ul><li>Select <strong>Flight Modes</strong> in Mandatory Hardware and assign modes as needed.</li></ul></li><li><p><strong><a href="https://ardupilot.org/copter/docs/connect-escs-and-motors.html" target="_blank" rel="noreferrer">Motor Test</a></strong></p><ul><li>Ensure safety protocols are followed.</li><li>Open &quot;Motor Test&quot; and verify propeller directions.</li></ul></li></ol><h2 id="additional-resources" tabindex="-1">Additional Resources <a class="header-anchor" href="#additional-resources" aria-label="Permalink to &quot;Additional Resources&quot;">​</a></h2><ul><li><a href="https://ardupilot.org/" target="_blank" rel="noreferrer">Ardupilot Documentation</a></li><li><a href="https://ardupilot.org/planner/docs/mission-planner-installation.html" target="_blank" rel="noreferrer">Mission Planner User Guide</a></li><li><a href="https://www.st.com/en/development-tools/stm32cubeprog.html" target="_blank" rel="noreferrer">STM32 Cube Programmer Documentation</a></li></ul><hr><p><strong><span class="note">Note:</span></strong> Always follow safety protocols during setup and testing to prevent damage to your drone or personal injury.</p>',23)]))}const m=o(a,[["render",i]]);export{h as __pageData,m as default};
